  ('locality-0c700c30-moex-00064', 'locality-0c700c30', 'locality-0c700c30-moex-113-d3ff7f6b', 'sub-locality-0c700c30-03', NULL, 'single_choice', '有關防疫保單之亂，下列敘述何者正確？', '["容易受感染的高風險族群，愈會購買防疫保單，此為道德危機問題；購買防疫險的個人，疏於 應有之防疫努力，此為逆向選擇問題", "容易受感染的高風險族群，愈會購買防疫保單，此為道德危機問題；購買防疫險的個人，疏於 應有之防疫努力，此亦為道德危機問題", "容易受感染的高風險族群，愈會購買防疫保單，此為逆向選擇問題；購買防疫險的個人，疏於 應有之防疫努力，此為道德危機問題", "容易受感染的高風險族群，愈會購買防疫保單，此為逆向選擇問題；購買防疫險的個人，疏於 應有之防疫努力，此亦為逆向選擇問題"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:13+00:00", "source_pdf_sha1": "73210569d047", "answer_pdf_sha1": "27b49f81005c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "314", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "統計"}'::jsonb, NULL),
  ('locality-0c700c30-moex-00065', 'locality-0c700c30', 'locality-0c700c30-moex-113-d3ff7f6b', 'sub-locality-0c700c30-03', NULL, 'single_choice', '有關公共財，下列敘述何者錯誤？', '["準公共財與公共財皆具排他性", "不壅塞且不收費的道路屬於純公共財", "付費的無線電視屬於準公共財", "公共財不具排他性，準公共財具排他性"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:13+00:00", "source_pdf_sha1": "73210569d047", "answer_pdf_sha1": "27b49f81005c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "314", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "統計"}'::jsonb, NULL),
  ('locality-0c700c30-moex-00066', 'locality-0c700c30', 'locality-0c700c30-moex-113-d3ff7f6b', 'sub-locality-0c700c30-03', NULL, 'single_choice', '某一位汽車經銷商於年初花了 90 萬元向汽車製造商買了一台今年度製造的新車，之後於年中以 100萬元賣給了小丁。小丁又於年底以95萬元賣給了小花。以上交易對今年度GDP的貢獻為何？', '["90萬元", "95萬元", "100萬元", "285萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:13+00:00", "source_pdf_sha1": "73210569d047", "answer_pdf_sha1": "27b49f81005c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "314", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "統計"}'::jsonb, NULL),
  ('locality-0c700c30-moex-00067', 'locality-0c700c30', 'locality-0c700c30-moex-113-d3ff7f6b', 'sub-locality-0c700c30-03', NULL, 'single_choice', '根據古典的貨幣數量學說，若一國貨幣供給為30兆，貨幣流通速度為2，則該國的名目GDP為何？', '["60兆", "30兆", "15兆", "不確定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:13+00:00", "source_pdf_sha1": "73210569d047", "answer_pdf_sha1": "27b49f81005c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "314", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "統計"}'::jsonb, NULL),
  ('locality-0c700c30-moex-00068', 'locality-0c700c30', 'locality-0c700c30-moex-113-d3ff7f6b', 'sub-locality-0c700c30-03', NULL, 'single_choice', '在梭羅的新古典成長模型（Solowneoclassicalgrowthmodel）中，假設經濟體系沒有資本折舊也 沒有技術進步，且資本的邊際產出等於0.15、人口成長率等於0.05、儲蓄率等於0.2。當此經濟 體系達到穩定狀態（steadystate），下列敘述何者正確？', '["人均資本存量低於黃金法則（goldenrule）水準", "人均資本存量等於黃金法則水準", "人均資本存量高於黃金法則水準", "無法確定人均資本存量低於或高於黃金法則水準 31860 50550"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:13+00:00", "source_pdf_sha1": "73210569d047", "answer_pdf_sha1": "27b49f81005c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "314", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "統計"}'::jsonb, NULL),
  ('locality-0c700c30-moex-00069', 'locality-0c700c30', 'locality-0c700c30-moex-113-d3ff7f6b', 'sub-locality-0c700c30-03', NULL, 'single_choice', '假設其他條件不變且政府的財政政策與中央銀行的貨幣政策均有效。根據 IS-LM 模型，當政府 減稅且中央銀行賣出債券時，下列敘述何者正確？', '["均衡所得會增加", "均衡所得會減少", "均衡利率會上升", "均衡利率會下降"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:13+00:00", "source_pdf_sha1": "73210569d047", "answer_pdf_sha1": "27b49f81005c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "314", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "統計"}'::jsonb, NULL),
  ('locality-0c700c30-moex-00070', 'locality-0c700c30', 'locality-0c700c30-moex-113-d3ff7f6b', 'sub-locality-0c700c30-03', NULL, 'single_choice', '當經濟體系處於流動性陷阱（liquiditytrap）時，下列敘述何者正確？', '["LM曲線呈現垂直線", "寬鬆貨幣政策能降低利率，激勵有效需求，使得所得增加", "經濟已從景氣谷底爬升進入繁榮期", "政府支出增加幾乎不影響利率變化，以致私人投資和消費需求幾乎沒有被排擠，因此，均衡所 得增加幅度很大"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:13+00:00", "source_pdf_sha1": "73210569d047", "answer_pdf_sha1": "27b49f81005c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "314", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "統計"}'::jsonb, NULL),
  ('locality-0c700c30-moex-00071', 'locality-0c700c30', 'locality-0c700c30-moex-113-d3ff7f6b', 'sub-locality-0c700c30-03', NULL, 'single_choice', '在小型開放總體經濟體系中，若淨出口（netexports）為負，則下列敘述何者正確？', '["國內支出大於產出", "儲蓄大於投資", "進口小於出口", "淨資本流出為正"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:13+00:00", "source_pdf_sha1": "73210569d047", "answer_pdf_sha1": "27b49f81005c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "314", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "統計"}'::jsonb, NULL),
  ('locality-0c700c30-moex-00072', 'locality-0c700c30', 'locality-0c700c30-moex-113-d3ff7f6b', 'sub-locality-0c700c30-03', NULL, 'single_choice', '某一個沒有生產原油的國家，其目前的產出低於充分就業產出。若世界原油價格上漲，根據凱因 斯學派，則該國名目利率將產生下列何種變化？', '["一定下降", "一定上升", "一定不變", "可能上升也可能下降"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:13+00:00", "source_pdf_sha1": "73210569d047", "answer_pdf_sha1": "27b49f81005c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "314", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "統計"}'::jsonb, NULL),
  ('locality-0c700c30-moex-00073', 'locality-0c700c30', 'locality-0c700c30-moex-113-d3ff7f6b', 'sub-locality-0c700c30-03', NULL, 'single_choice', '根據總合供給與總合需求模型的架構，有關總體經濟政策與衝擊對景氣循環影響，下列敘述何者 正確？', '["透過緊縮性貨幣政策讓總合需求線向右移動，以抑制景氣過度擴張的現象", "透過減稅措施刺激消費讓總合需求線向右移動，以避免景氣不佳引起的衰退", "總合供給線會因原物料價格上揚而向右移動，造成產出下滑的景氣收縮變化", "對未來經濟前景樂觀的預期，會讓總合供給線向右移動，帶動景氣擴張變化"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:13+00:00", "source_pdf_sha1": "73210569d047", "answer_pdf_sha1": "27b49f81005c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "314", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "統計"}'::jsonb, NULL)
